require(
    _encodeStateBitmap(currentState) & allowedStates != bytes32(0),
    ERC7579ExecutorUnexpectedOperationState(operationId, currentState, allowedStates)
);

for (uint256 i = 0; i < signingSigners.length; ++i) {
    if (!isSigner(account, signingSigners[i])) {
        return false;
    }
}

for (uint256 i = 0; i < signersLength; i++) {
    if (signatures[i].length != 0) {
        _signingSigners[regularIndex] = signingSigners[i];
        _signatures[regularIndex] = signatures[i];
        regularIndex++;
    }
}

if (initData.length > 96 && !installed) {
    (bytes[] memory signers, , uint64[] memory weights) = abi.decode(initData, (bytes[], uint64, uint64[]));
    _setSignerWeights(msg.sender, signers, weights);
}

for (uint256 i = 0; i < allSignersLength; ++i) {
    delete _extraWeights[account][allSigners[i]];
}

unchecked {
    // Safe cast, _setSignerWeights guarantees 1+_extraWeights is a uint64
    return uint64(isSigner(account, signer).toUint() * (1 + _extraWeights[account][signer]));
}

for (uint256 i = 0; i < bytes32Selectors.length; i++) {
    selectors_[i] = bytes4(bytes32Selectors[i]);
}

if (initData.length > 0) {
    bytes4[] memory selectors_ = abi.decode(initData, (bytes4[]));
    _addSelectors(msg.sender, selectors_);
}

for (uint256 i = 0; i < newSelectorsLength; i++) {
    if (_authorizedSelectors[account].add(newSelectors[i])) {
        emit ERC7579ExecutorSelectorAuthorized(account, newSelectors[i]);
    } // no-op if the selector is already in the set
}

for (uint256 i = 0; i < oldSelectorsLength; i++) {
    if (_authorizedSelectors[account].remove(oldSelectors[i])) {
        emit ERC7579ExecutorSelectorRemoved(account, oldSelectors[i]);
    } // no-op if the selector is not in the set
}

if (!refunded) {
    revert PaymasterERC20FailedRefund(token, prefundAmount, actualAmount, prefundContext);
}

return (
    bytes(""),
    _rawSignatureValidation(_signableUserOpHash(userOp, validAfter, validUntil), signature).packValidationData(
        validAfter,
        validUntil
    )
);

for (uint256 i = 0; i < attributes.length; ++i) {
    bytes4 selector = attributes[i].length < 0x04 ? bytes4(0) : bytes4(attributes[i]);
    require(supportsAttribute(selector), UnsupportedAttribute(selector));
}

return
            keccak256(key) == keccak256(abi.encodePacked("valid_key_1")) &&
            keccak256(signature) == keccak256(abi.encodePacked("valid_signature_1"));

return
            keccak256(key) == keccak256(abi.encodePacked("valid_key_2")) &&
            keccak256(signature) == keccak256(abi.encodePacked("valid_signature_2"));

if (from != address(0)) {
    uint256 unfrozen = available(from);
    require(unfrozen >= value, ERC20InsufficientUnfrozenBalance(from, value, unfrozen));
}

if (moduleTypeId == MODULE_TYPE_FALLBACK)
            // ERC-7579 requires this function to return bool, never revert. Check length to avoid out-of-bounds access.
            return additionalContext.length > 3 && $._fallbacks[bytes4(additionalContext[0:4])] == module;

if (allowOverride || $._links[chain].gateway == address(0)) {
    $._links[chain] = Link(gateway, counterpart);
    emit LinkRegistered(gateway, counterpart);
} else {
    revert LinkAlreadyRegistered(chain);
}

struct VestingWalletStorage {
    uint256 _released;
    mapping(address token => uint256) _erc20Released;
    uint64 _start;
    uint64 _duration;
}

struct GovernorCountingOverridableStorage {
    mapping(uint256 proposalId => ProposalVote) _proposalVotes;
}

struct GovernorCountingSimpleStorage {
    mapping(uint256 proposalId => ProposalVote) _proposalVotes;
}

struct GovernorPreventLateQuorumStorage {
    uint48 _voteExtension;

    mapping(uint256 proposalId => uint48) _extendedDeadlines;
}

struct GovernorSequentialProposalIdStorage {
    uint256 _latestProposalId;
    mapping(uint256 proposalHash => uint256 proposalId) _proposalIds;
}

struct GovernorSettingsStorage {
    // amount of token
    uint256 _proposalThreshold;
    // timepoint: limited to uint48 in core (same as clock() type)
    uint48 _votingDelay;
    // duration: limited to uint32 in core
    uint32 _votingPeriod;
}

struct GovernorStorageStorage {
    uint256[] _proposalIds;
    mapping(uint256 proposalId => ProposalDetails) _proposalDetails;
}
